import type { RuntimeCapabilities, PermissionModeDescriptor } from '../agent-runtime.js';

describe('RuntimeCapabilities', () => {
  it('accepts Claude-like declaration', () => {
    const caps: RuntimeCapabilities = {
      supportsResume: true,
      supportsMcp: true,
      supportsCostTracking: true,
      supportsToolApproval: true,
      supportsQuestionPrompt: true,
      supportsPlugins: true,
      permissionModes: {
        supported: true,
        values: [
          { id: 'default', label: 'Default' },
          { id: 'acceptEdits', label: 'Accept edits' },
          { id: 'plan', label: 'Plan' },
          { id: 'bypassPermissions', label: 'Bypass permissions' },
        ],
      },
      features: { claudeSkills: true },
    };
    expect(caps.permissionModes.values).toHaveLength(4);
  });

  it('accepts runtime that does not support permission modes', () => {
    const caps: RuntimeCapabilities = {
      supportsResume: false,
      supportsMcp: false,
      supportsCostTracking: false,
      supportsToolApproval: false,
      supportsQuestionPrompt: false,
      supportsPlugins: false,
