  constructor(protected readonly ctx: RuntimeAdapterContext) {}

  // ============================================================
  // Behavioral logic — concrete, lives in the base. Same for every runtime.
  // ============================================================

  /** Main entry point: stream a message through the runtime, handle retries and delivery. */
  async streamMessage(message: InboundMessage): Promise<void> {
    // retry loop, queueing, delivery. Delegates to runtime-specific hooks below.
  }

  /** Shared delivery semantics: reliable delivery with back-off. */
  protected async deliver(event: OutboundEvent): Promise<void> {
    // ...
