**Refactor pattern:**
```ts
import { RuntimeAdapter, type RuntimeAdapterContext } from '../runtime-adapter.js';
import type { ClaudeCodeAgentRuntime } from './types.js';

export class ClaudeCodeAdapter extends RuntimeAdapter {
  constructor(
    ctx: RuntimeAdapterContext,
    private readonly runtime: ClaudeCodeAgentRuntime,
  ) {
    super(ctx);
  }

  protected async openSession(sessionId: string) {
    // Claude-specific: open via @anthropic-ai/claude-agent-sdk
    return this.runtime.openSession(sessionId);
  }

  protected normalizeEvent(raw: unknown): OutboundEvent {
    // Claude-specific: map SDKMessage → OutboundEvent
    return mapSdkMessage(raw as SDKMessage);
  }

  protected async closeSession(handle: RuntimeSessionHandle) {
    // Claude-specific teardown
    await this.runtime.closeSession(handle);
  }

  // Any truly-Claude-only behavior stays here; nothing moves to the base unless it would
  // apply identically to test-mode and codex adapters.
}
```

**Behavioral-parity checklist:**
Before/after this refactor, the following behaviors MUST be identical:
- Retry count on transient SDK errors.
- Event ordering within a single session.
- Delivery semantics on the outbound queue.
- Error taxonomy surfaced to callers.

