import { RuntimeAdapter, type RuntimeAdapterContext } from '../runtime-adapter.js';
import type { TestModeRuntime } from '@dorkos/server/runtimes/test-mode';

/**
 * Permanent Relay adapter for the test-mode runtime. Not for production — used as a
 * standing integration fixture to prove the generalized composition works.
 *
 * If you find yourself importing anything Claude-specific here, the base class design
 * is leaking — fix the base, not this subclass.
 */
export class TestModeAdapter extends RuntimeAdapter {
  constructor(
    ctx: RuntimeAdapterContext,
    private readonly runtime: TestModeRuntime,
  ) {
    super(ctx);
  }

  protected async openSession(sessionId: string) {
    return this.runtime.openSession(sessionId);
  }

  protected normalizeEvent(raw: unknown): OutboundEvent {
    // test-mode emits events that are already close to OutboundEvent shape;
    // this method proves the normalization pipeline handles a second runtime's
    // event shape without modification to the base.
    return raw as OutboundEvent;
  }

  protected async closeSession() {
    // test-mode has no-op teardown — this is intentional and OK.
  }
}
