**Before/after shape:**
```ts
// Before:
import type { ClaudeCodeAgentRuntimeLike } from '@dorkos/relay/adapters/claude-code/types';

class AdapterManager {
  constructor(private runtime: ClaudeCodeAgentRuntimeLike) {}
  async dispatch(message: InboundMessage) {
    // always calls claude-specific path
  }
}

// After:
import type { RuntimeAdapter } from '@dorkos/relay/adapters';
import { runtimeRegistry } from '../core/runtime-registry.js';

class AdapterManager {
  constructor(private adapters: Map<string, RuntimeAdapter>) {}

  async dispatch(message: InboundMessage) {
    const runtimeType = await runtimeRegistry.getSessionRuntimeType(message.sessionId);
    const adapter = this.adapters.get(runtimeType);
    if (!adapter) throw new AdapterNotRegisteredError(runtimeType, message.sessionId);
    return adapter.streamMessage(message);
  }

  register(runtimeType: string, adapter: RuntimeAdapter) {
    this.adapters.set(runtimeType, adapter);
  }
}
```

